class Any_EncuestarFixer {
  constructor(mode) {
    this.MODE = mode ?? "RANDOM";
    this.DELAY = 700;
    this.GRUPO_PREGUNTA = 5;
    this.TEXT_COMPLETAR = "Completar";
    this.TEXT_OK = "OK";
    this.SELECTOR_LINKS =
      'a[data-original-title="Completar Encuesta"], a[title="Completar Encuesta"]'; // agrega para otrass webs
  }

  sleep(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  async ejecutarEncuestasConControl() {
    const links = document.querySelectorAll(this.SELECTOR_LINKS);

    if (links.length === 0) {
      return false;
    }

    for (let index = 0; index < links.length; index++) {
      const link = links[index];

      try {
        link.dispatchEvent(
          new MouseEvent("click", {
            bubbles: true,
            cancelable: true,
            view: window,
          }),
        );
      } catch (error) {}

      await this.sleep(this.DELAY);
    }

    return true;
  }

  async llenarEncuestas(modo) {
    const radios = document.querySelectorAll('input[type="radio"]');

    if (radios.length === 0) {
      return false;
    }

    let pregunta = 1;

    for (let i = 0; i < radios.length; i += this.GRUPO_PREGUNTA) {
      const grupo = Array.from(radios).slice(i, i + this.GRUPO_PREGUNTA);

      if (grupo.length < this.GRUPO_PREGUNTA) continue;

      let indexSeleccionado = 0;

      switch (modo.toUpperCase()) {
        case "BAD":
          indexSeleccionado = 0;
          break;
        case "REGULAR":
          indexSeleccionado = 1;
          break;
        case "GOOD":
          indexSeleccionado = 2;
          break;
        case "VERY GOOD":
          indexSeleccionado = 3;
          break;
        case "EXCELLENT":
          indexSeleccionado = 4;
          break;
        default:
          indexSeleccionado = Math.floor(Math.random() * grupo.length);
      }

      try {
        const radio = grupo[indexSeleccionado];

        radio.checked = true;
        radio.dispatchEvent(new Event("change", { bubbles: true }));
        radio.dispatchEvent(new Event("click", { bubbles: true }));
      } catch (error) {}

      pregunta++;
      await this.sleep(150);
    }

    return true;
  }

  async confirmar_Encuestas() {
    const spans = document.querySelectorAll("span");
    let totalClicks = 0;

    for (let index = 0; index < spans.length; index++) {
      const span = spans[index];
      const texto = span.textContent.trim();

      if (texto !== this.TEXT_COMPLETAR) continue;

      try {
        span.dispatchEvent(
          new MouseEvent("click", {
            bubbles: true,
            cancelable: true,
            view: window,
          }),
        );

        totalClicks++;

        await this.sleep(Math.floor(Math.random() * 2000) + 500);

        const botones = document.querySelectorAll("button");

        botones.forEach((btn) => {
          if (btn.textContent.trim() === this.TEXT_OK) {
            btn.dispatchEvent(
              new MouseEvent("click", {
                bubbles: true,
                cancelable: true,
                view: window,
              }),
            );
          }
        });

        await this.sleep(Math.floor(Math.random() * 2000) + 500);
      } catch (error) {}
    }

    return true;
  }

  async start() {
    const one = await this.ejecutarEncuestasConControl();
    const two = await this.llenarEncuestas(this.MODE);
    const end = await this.confirmar_Encuestas();

    if (one && two && end) {
           console.log("✅ Proceso completado");
           window.open("https://www.instagram.com/bradez__rd/", "_blank");
    }
  }

  async ui() {
    const old = document.getElementById("encuestar-fixer-ui");
    if (old) old.remove();

    const css = `
    #encuestar-fixer-ui{
        position:fixed;
        inset:0;
        z-index:999999999;
        background:linear-gradient(135deg,#050505,#111,#1a1a1a);
        display:flex;
        align-items:center;
        justify-content:center;
        font-family:Arial, sans-serif;
        color:#fff;
    }

    #encuestar-fixer-ui .box{
        width:95%;
        max-width:650px;
        background:#121212;
        border:1px solid rgba(255,255,255,.08);
        border-radius:22px;
        padding:30px;
        box-shadow:0 25px 80px rgba(0,0,0,.55);
        text-align:center;
    }

    #encuestar-fixer-ui img{
        width:120px;
        height:120px;
        border-radius:50%;
        object-fit:cover;
        margin-bottom:15px;
        border:3px solid #fff;
    }

    #encuestar-fixer-ui h1{
        margin:0;
        font-size:28px;
    }

    #encuestar-fixer-ui p{
        opacity:.8;
        margin:8px 0 20px;
    }

    #encuestar-fixer-ui select{
        width:100%;
        padding:14px;
        border:none;
        border-radius:12px;
        font-size:16px;
        margin-bottom:20px;
        outline:none;
    }

    #encuestar-fixer-ui button{
        width:100%;
        padding:15px;
        border:none;
        border-radius:12px;
        font-size:18px;
        font-weight:bold;
        cursor:pointer;
        background:#00c853;
        color:#fff;
        transition:.2s;
    }

    #encuestar-fixer-ui button:hover{
        transform:scale(1.02);
        background:#00e676;
    }
#encuestar-fixer-ui .social{
    margin-top:18px;
    display:flex;
    flex-direction:row !important;
    justify-content:center;
    align-items:center;
    gap:14px;
    flex-wrap:nowrap;
    position:relative;
    clear:both;
}

#encuestar-fixer-ui .close{
    width:100%;
    margin-top:14px;
    margin-bottom:18px;
    display:block;
    position:relative;
    z-index:2;
}

#encuestar-fixer-ui .social a{
    width:52px;
    height:52px;
    display:inline-flex;
    justify-content:center;
    align-items:center;
    border-radius:16px;
    flex-shrink:0;
}

#encuestar-fixer-ui .social img{
    width:24px;
    height:24px;
    display:block;
}

    #encuestar-fixer-ui .close{
        margin-top:15px;
        background:#d50000;
    }
    `;

    const style = document.createElement("style");
    style.innerHTML = css;
    document.head.appendChild(style);

    const ui = document.createElement("div");
    ui.id = "encuestar-fixer-ui";

    ui.innerHTML = `
        <div class="box">

            <img src='data:image/png;base64,'>

            <h1>EncuestarFixer</h1>
            <p>¿Qué tal tu experiencia hoy?</p>

            <select id="fixer-mode">
                <option value="BAD">😡 BAD</option>
                <option value="REGULAR">😐 REGULAR</option>
                <option value="GOOD">🙂 GOOD</option>
                <option value="VERY GOOD">😎 VERY GOOD</option>
                <option value="EXCELLENT" selected>🔥 EXCELLENT</option>
                <option value="RANDOM">🎲 RANDOM</option>
            </select>

            <button id="fixer-start">🚀 START</button>
            <button class="close" id="fixer-close">❌ CLOSE</button>

            <div class="social">
            
                <a href="https://www.instagram.com/bradez__rd/" target="_blank" title="Instagram">
                    <img src="https://cdn.simpleicons.org/instagram/white">
                </a>
            
                <a href="https://www.paypal.com/donate?business=mendezdarlin750@gmail.com&no_recurring=0&item_name=GRACIAS+PODRE+COMER+O+COMPRARME+UN+CAFE&currency_code=USD" target="_blank" title="paypal">
                    <img src="https://cdn.simpleicons.org/paypal/white">
                </a>
            
                <a href="https://github.com/bradez-rd" target="_blank" title="GitHub">
                    <img src="https://cdn.simpleicons.org/github/white">
                </a>
            
                <a href="https://www.youtube.com/@bradez-rd" target="_blank" title="YouTube">
                    <img src="https://cdn.simpleicons.org/youtube/white">
                </a>
            
            </div>

        </div>
    `;

    document.body.appendChild(ui);
    document.body.style.overflow = "hidden";

    document.getElementById("fixer-close").onclick = () => {
      ui.remove();
      document.body.style.overflow = "";
    };

    document.getElementById("fixer-start").onclick = () => {
      const mode = document.getElementById("fixer-mode").value;
      ui.remove();
      document.body.style.overflow = "";
      this.start(mode);
    };
    return true;
  }

async init(selector = this.SELECTOR_LINKS) {
  console.log("Iniciando observador con selector:", selector);

  let observer = null;

  const check = () => {
    try {
      const el = document.querySelector(selector);

      console.log("Buscando elemento...");

      if (el) {
        console.log("FOUND", "Elemento detectado:", el);

        // ejecutar UI
        if (typeof this.ui === "function") {
          console.log("UI", "Ejecutando UI()");
          this.ui();
        }

        // detener observer
        if (observer) {
          console.log("STOP", "Desconectando MutationObserver...");
          observer.disconnect();
          observer = null;
        }

        return true;
      }

      console.log("Aún no aparece el elemento...");
      return false;
    } catch (e) {
      console.log("check()", e);
      return false;
    }
  };

  // primera ejecución inmediata
  check();

  // observer
  observer = new MutationObserver(() => {
    check();
  });

  console.log("OBSERVER", "Observando DOM...");
  observer.observe(document.body, {
    childList: true,
    subtree: true,
  });

  return true;
}

}

const Program = await new Any_EncuestarFixer().init();

